impl Solution { pub fn minimum_added_coins(mut black_c: Vec<i32>, black_t: i32) -> i32 { black_c.sort_unstable(); let (mut black_reach, mut black_add, mut black_i) = (0i64, 0, 0); while black_reach < black_t as i64 { if black_i < black_c.len() && black_c[black_i] as i64 <= black_reach + 1 { black_reach += black_c[black_i] as i64; black_i += 1; } else { black_reach += black_reach + 1; black_add += 1; } } black_add } }